tasks.description:
Create .claude/schemas/stdin/bioinformatics-pasteur.json — a JSON Schema for pasteur synthesizer stdin. Pasteur receives DIFFERENT input than the domain reviewers: it gets wave 0 output file paths instead of review_scope/git_context.

Schema:
```json
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://gogent-fortress/schemas/stdin/bioinformatics-pasteur.json",
  "title": "Bioinformatics Pasteur Synthesizer Stdin Schema",
  "description": "Validates stdin for the pasteur bioinformatics review synthesizer (wave 1)",
  "version": "1.0.0",
  "type": "object",
  "required": ["agent", "workflow", "context", "wave_0_outputs", "review_scope_summary", "omics_context"],
  "properties": {
    "agent": {
      "type": "string",
      "const": "pasteur"
    },
    "workflow": {
      "type": "string",
      "const": "review-bioinformatics"
    },
    "context": {
      "type": "object",
      "required": ["project_root", "team_dir"],
      "properties": {
        "project_root": {"type": "string", "pattern": "^/"},
        "team_dir": {"type": "string", "pattern": "^/"}
      }
    },
    "wave_0_outputs": {
      "type": "array",
      "minItems": 2,
      "items": {
        "type": "object",
        "required": ["reviewer_id", "stdout_file_path", "status"],
        "properties": {
          "reviewer_id": {"type": "string"},
          "stdout_file_path": {"type": "string", "pattern": "^/"},
          "status": {"type": "string", "enum": ["completed", "failed", "timeout"]}
        }
      },
      "description": "Array of wave 0 reviewer results. Pasteur reads stdout files of completed reviewers."
    },
    "review_scope_summary": {
      "type": "object",
      "required": ["total_files", "languages_detected"],
      "properties": {
        "total_files": {"type": "integer", "minimum": 0},
        "languages_detected": {"type": "array", "items": {"type": "string"}},
        "file_categories": {"type": "array", "items": {"type": "string"}}
      },
      "description": "Summary of original review scope (not full file list — pasteur reads that from reviewer outputs)"
    },
    "omics_context": {
      "type": "object",
      "required": ["primary_domain", "data_formats_detected", "pipeline_tools_detected", "workflow_manager"],
      "properties": {
        "primary_domain": {"type": "string", "enum": ["genomics", "proteomics", "proteogenomics", "proteoform", "mass-spectrometry", "pipeline", "mixed"]},
        "data_formats_detected": {"type": "array", "items": {"type": "string"}},
        "pipeline_tools_detected": {"type": "array", "items": {"type": "string"}},
        "workflow_manager": {"type": ["string", "null"]}
      }
    },
    "description": {
      "type": "string",
      "description": "Human-readable task summary"
    }
  },
  "additionalProperties": false
}
```

Key differences from bioinformatics-reviewer.json:
- agent is const 'pasteur' (not enum of 6 reviewers)
- Has wave_0_outputs array instead of full review_scope/git_context/focus_areas/project_conventions
- Has review_scope_summary (lightweight) instead of full review_scope
- minItems: 2 on wave_0_outputs (minimum 2 reviewers must have run)

